import static org.mockito.Mockito.*;

public class ReliableTxServiceTest extends TestBase {

    @Resource
    private IReliableTxService reliableTxService;

    @MockitoBean
    private ISystemConfigRepository systemConfigRepository;

    @MockitoBean
    private L2Client l2Client;

    @MockitoBean
    private IRollupRepository rollupRepository;

    @MockitoBean
    private IOracleRepository oracleRepository;

    @MockitoBean
    private ProverControllerClient proverControllerClient;

    @MockitoBean
    private TraceServiceClient traceServiceClient;

    @MockitoBean
    private L1Client l1Client;

    @MockitoBean
    private RollupConfig rollupConfig;

    @MockitoBean
    private DistributedTaskEngine distributedTaskEngine;

    @MockitoBean(name = "l1Web3j")
    private Web3j l1Web3j;

    @MockitoBean(name = "l1ChainId")
    private BigInteger l1ChainId;

    private ReliableTransactionDO reliableTransactionDO;

    @Before
    public void init() {
        reliableTransactionDO = ReliableTransactionDO.builder()
                .transactionType(TransactionTypeEnum.BATCH_TEE_PROOF_COMMIT_TX)
                .batchIndex(BigInteger.valueOf(1))
                .chainType(ChainTypeEnum.LAYER_ONE)
                .senderAccount("0x863df6bfa4469f3ead0be8f9f2aae51c91a907b4")
                .originalTxHash("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9")
                .latestTxHash("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9")
                .rawTx(HexUtil.decodeHex(""))
                .latestTxSendTime(new Date())
                .retryCount(0)
                .state(ReliableTransactionStateEnum.TX_PENDING)
                .nonce(1L)
                .build();
    }

    @Test
    public void testProcessL1PendingTx_TxNotFound() {
        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(reliableTransactionDO));
        when(l1Client.queryTx(notNull())).thenReturn(null);
        EthSendTransaction ethSendTransaction = new EthSendTransaction();
        ethSendTransaction.setResult("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9");
        reliableTransactionDO.setLatestTxHash("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9");
        when(l1Client.sendRawTx(notNull())).thenReturn(ethSendTransaction);

        when(l1Client.queryTxCount(notNull(), notNull())).thenReturn(BigInteger.valueOf(1));

        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getLatestTxHash().equals(ethSendTransaction.getTransactionHash())));

        ReflectUtil.setFieldValue(reliableTxService, "l1NoncePolicy", EthNoncePolicyEnum.NORMAL);
        TransactionInfo transactionInfo = TransactionInfo.builder()
                .txHash(Numeric.toHexString(RandomUtil.randomBytes(32)))
                .sendTxTime(new Date())
                .rawTx("123".getBytes())
                .senderAccount("0x863df6bfa4469f3ead0be8f9f2aae51c91a907b4")
                .nonce(BigInteger.valueOf(2))
                .build();
        when(l1Client.resendRollupTx(notNull(), anyString())).thenReturn(transactionInfo);
        clearInvocations(rollupRepository);
        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getLatestTxHash().equals(transactionInfo.getTxHash())));
    }

    @Test
    public void testProcessL1PendingTx_TxNotPackaged() {
        when(l1Client.queryTx(notNull())).thenReturn(new Transaction());
        reliableTransactionDO.setLatestTxSendTime(DateUtil.lastMonth());
        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(reliableTransactionDO));
        TransactionInfo transactionInfo = TransactionInfo.builder()
                .txHash(Numeric.toHexString(RandomUtil.randomBytes(32)))
                .sendTxTime(new Date())
                .rawTx("123".getBytes())
                .senderAccount("0x863df6bfa4469f3ead0be8f9f2aae51c91a907b4")
                .nonce(BigInteger.valueOf(2))
                .build();
        when(l1Client.speedUpRollupTx(notNull())).thenReturn(transactionInfo);
        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getLatestTxHash().equals(transactionInfo.getTxHash())));

        reliableTransactionDO.setLatestTxSendTime(DateUtil.lastMonth());
        when(l1Client.speedUpRollupTx(notNull())).thenThrow(L1ContractWarnException.class);
        clearInvocations(rollupRepository);
        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getState() == ReliableTransactionStateEnum.BIZ_SUCCESS));
    }

    @Test
    public void testProcessL1PendingTx_TxConfirmed() {
        when(rollupRepository.getReliableTransaction(
                eq(reliableTransactionDO.getChainType()), eq(reliableTransactionDO.getBatchIndex()), eq(TransactionTypeEnum.BATCH_COMMIT_TX))
        ).thenReturn(ReliableTransactionDO.builder().state(ReliableTransactionStateEnum.TX_PACKAGED).build());
        when(l1Client.queryTx(notNull())).thenReturn(new Transaction());
        reliableTransactionDO.setLatestTxSendTime(DateUtil.date());
        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(reliableTransactionDO));
        when(l1Client.queryLatestBlockNumber(notNull())).thenReturn(BigInteger.valueOf(15), BigInteger.valueOf(100L));
        TransactionReceipt receipt = new TransactionReceipt();
        receipt.setStatus("0x0");
        receipt.setBlockNumber("0x10");
        when(l1Client.queryTxReceipt(notNull())).thenReturn(receipt);

        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getState() == ReliableTransactionStateEnum.TX_FAILED));

        receipt.setStatus("0x1");
        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransactionState(notNull(), notNull(), notNull(), argThat(argument -> argument == ReliableTransactionStateEnum.TX_PACKAGED));

        reliableTxService.processL1NotFinalizedTx();
        verify(rollupRepository, times(1)).updateReliableTransactionState(notNull(), notNull(), notNull(), argThat(argument -> argument == ReliableTransactionStateEnum.TX_SUCCESS));
    }

    @Test
    public void testProcessL1PendingTx_CreateL2GasFeedRequest() throws NoSuchFieldException {
        reliableTransactionDO.setLatestTxSendTime(DateUtil.date());
        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(reliableTransactionDO));
        when(l1Client.queryTx(notNull())).thenReturn(new Transaction());
        // tx confirmed
        TransactionReceipt receipt = new TransactionReceipt();
        receipt.setStatus("0x1");
        receipt.setBlockNumber("0x0A");
        when(l1Client.queryTxReceipt(notNull())).thenReturn(receipt);
        when(l1Client.queryLatestBlockNumber(notNull())).thenReturn(BigInteger.valueOf(15));

        reliableTxService.processL1NotFinalizedTx();
        verify(oracleRepository, times(1)).saveRollupTxReceipt(notNull(), argThat(argument -> argument == OracleTypeEnum.L2_GAS_ORACLE), argThat(argument -> argument == OracleRequestTypeEnum.L2_BATCH_PROVE), notNull());

        ReflectUtil.setFieldValue(reliableTxService, ReliableTxServiceImpl.class.getDeclaredField("baseProofType"), OracleBaseProofTypeEnum.ZK_PROOF);
        reliableTxService.processL1NotFinalizedTx();
        verify(oracleRepository, times(1)).saveRollupTxReceipt(notNull(), argThat(argument -> argument == OracleTypeEnum.L2_GAS_ORACLE), argThat(argument -> argument == OracleRequestTypeEnum.L2_BATCH_PROVE), notNull());

        reliableTransactionDO.setTransactionType(TransactionTypeEnum.BATCH_ZK_PROOF_COMMIT_TX);
        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(reliableTransactionDO));
        reliableTxService.processL1NotFinalizedTx();
        verify(oracleRepository, times(2)).saveRollupTxReceipt(notNull(), argThat(argument -> argument == OracleTypeEnum.L2_GAS_ORACLE), argThat(argument -> argument == OracleRequestTypeEnum.L2_BATCH_PROVE), notNull());
    }

    @Test
    public void testRetryFailedTx() {
        var tx = RollupRepositoryTest.randomReliableTransactionDOs(1, ReliableTransactionStateEnum.TX_FAILED).get(0);
        tx.setTransactionType(TransactionTypeEnum.BATCH_TEE_PROOF_COMMIT_TX);
        tx.setRawTx(reliableTransactionDO.getRawTx());
        tx.setRetryCount(0);
        when(rollupRepository.getFailedReliableTransactions(anyInt(), anyInt()))
                .thenReturn(ListUtil.toList(tx));
        when(rollupRepository.getReliableTransaction(eq(ChainTypeEnum.LAYER_ONE), eq(tx.getBatchIndex()), eq(TransactionTypeEnum.BATCH_COMMIT_TX)))
                .thenReturn(ReliableTransactionDO.builder().state(ReliableTransactionStateEnum.TX_PACKAGED).build());
        when(rollupRepository.getReliableTransaction(eq(ChainTypeEnum.LAYER_ONE), eq(tx.getBatchIndex().subtract(BigInteger.ONE)), eq(TransactionTypeEnum.BATCH_TEE_PROOF_COMMIT_TX)))
                .thenReturn(ReliableTransactionDO.builder().state(ReliableTransactionStateEnum.TX_PACKAGED).build());
        when(l1Client.resendRollupTx(notNull(), anyString())).thenReturn(TransactionInfo.builder()
                .nonce(BigInteger.valueOf(1))
                .txHash(Numeric.toHexString(RandomUtil.randomBytes(32))).build());
        when(l1Client.lastCommittedBatch(notNull())).thenReturn(tx.getBatchIndex());

        reliableTxService.retryFailedTx();

        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(
                x -> x.getRetryCount() == 1 && x.getState() == ReliableTransactionStateEnum.TX_PENDING
        ));
    }

    @Test
    public void testProcessL2PendingTx_TxNotFound() {
        // lost base fee feed tx
        var mockBaseFeeFeedTx = mockReliableTransactionDO(TransactionTypeEnum.L2_ORACLE_BASE_FEE_FEED_TX, 2, ChainTypeEnum.LAYER_TWO, ReliableTransactionStateEnum.TX_PENDING);

        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(mockBaseFeeFeedTx));
        when(l2Client.queryTx(notNull())).thenReturn(null);

        EthSendTransaction ethSendTransaction = new EthSendTransaction();
        ethSendTransaction.setResult("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9");

        reliableTxService.processL2NotFinalizedTx();
        verify(rollupRepository, times(1)).getNotFinalizedReliableTransactions(notNull(), anyInt());
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getLatestTxHash().equals(ethSendTransaction.getTransactionHash())));

        // lost batch fee feed tx
        var mockBatchFeeFeedTx = mockReliableTransactionDO(TransactionTypeEnum.L2_ORACLE_BATCH_FEE_FEED_TX, 3, ChainTypeEnum.LAYER_TWO, ReliableTransactionStateEnum.TX_PENDING);

        when(rollupRepository.getNotFinalizedReliableTransactions(notNull(), anyInt())).thenReturn(ListUtil.toList(mockBatchFeeFeedTx));

        EthSendTransaction ethSendTransaction1 = new EthSendTransaction();
        ethSendTransaction1.setResult("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9");

        clearInvocations(rollupRepository);
        reliableTxService.processL2NotFinalizedTx();
        verify(rollupRepository, times(1)).getNotFinalizedReliableTransactions(notNull(), anyInt());
        verify(rollupRepository, times(1)).updateReliableTransaction(argThat(argument -> argument.getLatestTxHash().equals(ethSendTransaction1.getTransactionHash())));
    }

    private ReliableTransactionDO mockReliableTransactionDO(TransactionTypeEnum txType, int batchIndex, ChainTypeEnum chainType, ReliableTransactionStateEnum txState) {
        return ReliableTransactionDO.builder()
                .transactionType(txType)
                .batchIndex(BigInteger.valueOf(batchIndex))
                .chainType(chainType)
                .senderAccount("0x863df6bfa4469f3ead0be8f9f2aae51c91a907b4")
                .originalTxHash("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9")
                .latestTxHash("0x05f71e1b2cb4f03e547739db15d080fd30c989eda04d37ce6264c5686e0722c9")
                .latestTxSendTime(new Date())
                .retryCount(0)
                .state(txState)
                .nonce(1L)
                .build();
    }
}
